#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int zeros = 0;
        int non_zeros = 0;
        for (int i = 0; i < N; i++) {
            int x;
            scanf("%d", &x);
            if (x == 0) zeros++;
            else non_zeros++;
        }
        long long result = 1;
        if (K == 0) {
            printf("1\n");
        } else if (K % 2 == 0) {
            for (int i = 0; i < K; i++) {
                result = (result * (non_zeros - i)) % MOD;
                result = (result * pow(i + 1, MOD - 2, MOD)) % MOD;
            }
            printf("%lld\n", result);
        } else {
            for (int i = 0; i < K - 1; i++) {
                result = (result * (non_zeros - i)) % MOD;
                result = (result * pow(i + 1, MOD - 2, MOD)) % MOD;
            }
            result = (result * non_zeros) % MOD;
            printf("%lld\n", result);
        }
    }
    return 0;
}

